#!/usr/bin/env python3
"""Assemble the ALIGNED greedy-target XL dataset in the train_p2_xl `--dataset` format:
reuse the frozen SSM contexts already cached in real_context_dataset_xl.npz (row-aligned to
its meta prompt_ids) and swap the UNFITTABLE real-corpus targets for the regenerated
mamba-GREEDY continuations (greedy_targets_cache.jsonl). Keeps ONLY rows whose greedy target
finished. Writes greedy_context_dataset_xl.npz + .meta.json.

Run: python3 build_greedy_dataset.py   # after (or during) regen_greedy_targets.py
"""
import json, os
import numpy as np

_HERE = os.path.dirname(os.path.abspath(__file__))
XL_NPZ = os.path.join(_HERE, "real_context_dataset_xl.npz")
XL_META = os.path.join(_HERE, "real_context_dataset_xl.meta.json")
CACHE = os.path.join(
    "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/"
    "dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad", "greedy_targets_cache.jsonl")
OUT_NPZ = os.path.join(_HERE, "greedy_context_dataset_xl.npz")
OUT_META = os.path.join(_HERE, "greedy_context_dataset_xl.meta.json")


def main():
    z = np.load(XL_NPZ)
    meta = json.load(open(XL_META))
    per_layer, ssm, finalh = z["per_layer_hidden"], z["ssm_state"], z["final_hidden"]
    N = per_layer.shape[0]
    rows = {}
    if os.path.exists(CACHE):
        for line in open(CACHE):
            try:
                r = json.loads(line); rows[int(r["row"])] = r["greedy"]
            except Exception:
                pass
    keep = sorted(k for k in rows if 0 <= k < N)
    print(f"greedy rows available: {len(keep)}/{N}")
    if not keep:
        raise SystemExit("no greedy rows yet")
    idx = np.array(keep)
    tgt = np.array([rows[k] for k in keep], dtype=np.int64)
    np.savez_compressed(OUT_NPZ, per_layer_hidden=per_layer[idx], ssm_state=ssm[idx],
                        final_hidden=finalh[idx], target_ids=tgt)
    om = {"K": tgt.shape[1], "n": len(keep), "prompt_len": meta.get("prompt_len", 6),
          "hidden_dim": 2560, "d_state": 16, "num_mem_slots": 16, "model": "mamba-2.8b",
          "vocab_size": 50280, "canary": meta.get("canary"),
          "target_kind": "mamba-2.8b-greedy-continuation (ALIGNED, regenerated for the same "
                         "XL prompts whose real-corpus targets proved unfittable)",
          "prompts": [meta["prompts"][k] for k in keep],
          "prompt_ids": [meta["prompt_ids"][k] for k in keep],
          "target_ids": tgt.tolist(),
          "source_rows": keep}
    json.dump(om, open(OUT_META, "w"))
    dist = len(set(map(tuple, tgt.tolist())))
    V = len(set(int(x) for x in tgt.reshape(-1)))
    print(f"assembled -> {OUT_NPZ}  n={len(keep)}  distinct-blocks {dist}  greedy-vocab V={V}")


if __name__ == "__main__":
    main()
